INSERT INTO members_products (id, data, group_id, group_name, group_order, variant_order) VALUES ('members-tirz-10mg', '{"id":"members-tirz-10mg","name":"Tirzepatide (10mg)","price":79,"category":"Metabolic & GLP-1 Related","quantityLabel":"10mg","image":"HATriz10.png","cas":"2023788-19-2","molecularWeight":"4813.48 g/mol","description":"Dual GIP/GLP-1 receptor agonist studied extensively in metabolic and adipose tissue research.","researchNotes":"Preclinical animal studies have shown tirzepatide activates both GLP-1 and GIP receptors, resulting in significant reductions in body weight, food intake, and improved glucose homeostasis. Research in obese and diabetic rodent models demonstrated superior effects on insulin sensitivity and lipid metabolism compared to single agonists. In vitro and in vivo work has explored its dual-incretin mechanism and long-acting pharmacokinetics.","form":"Lyophilized powder (vial)","purity":"≥99% (third-party tested)","storage":"Refrigerate at 2–8°C after reconstitution"}'::jsonb, 'members-tirz-10mg', 'Tirzepatide', 2, 0) ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, group_id = EXCLUDED.group_id, group_name = EXCLUDED.group_name, group_order = EXCLUDED.group_order, variant_order = EXCLUDED.variant_order, updated_at = now();
